import { test, expect } from '@playwright/test';

test('Amazon SG - Search for gibberish and validate no results message', async ({ page }) => {
  // 1. Launch browser → Amazon SG.
  await page.goto('https://www.amazon.sg/');

  // 2. Search for "asdasd123!@#".
  const searchBox = page.getByRole('combobox', { name: 'Search' });
  await expect(searchBox).toBeVisible({ timeout: 10000 });
  await searchBox.fill('asdasd123!@#');
  const searchButton = page.getByRole('button', { name: 'Go' });
  await expect(searchButton).toBeVisible({ timeout: 5000 });
  await Promise.all([
    page.waitForNavigation({ waitUntil: 'domcontentloaded' }),
    searchButton.click(),
  ]);

  // 3. Wait for results page.
  await expect(page).toHaveURL(/k=asdasd123!@#/);

  // 4. Validate "no results" or limited results message appears.
  // Amazon SG may show: "No results for asdasd123!@#" or "did not match any products"
  // Try both possible messages
  const noResultsLocator = page.getByText('No results for', { exact: false });
  const didNotMatchLocator = page.getByText('did not match any products', { exact: false });

  const noResultsVisible = await noResultsLocator.isVisible().catch(() => false);
  const didNotMatchVisible = await didNotMatchLocator.isVisible().catch(() => false);

  expect(
    noResultsVisible || didNotMatchVisible
  ).toBeTruthy();

  // 5. Close browser.
  // (Playwright test runner handles browser closure automatically)
});
